@@ -926,6 +926,21 @@ bool RecurrenceDescriptor::isReductionPHI(PHINode *Phi, Loop *TheLoop,
                                           DemandedBits *DB, AssumptionCache *AC,
                                           DominatorTree *DT,
                                           ScalarEvolution *SE) {
+  // If the recurrence is an integer add/sub of a loop-invariant zero, it's not a
+  // reduction.
+  if (Phi->hasOneUse()) {
+    if (auto *I = dyn_cast<Instruction>(Phi->user_back())) {
+      if (I->getOpcode() == Instruction::Add ||
+          I->getOpcode() == Instruction::Sub) {
+        unsigned OpIdx = (I->getOperand(0) == Phi) ? 0 : 1;
+        if (auto *C = dyn_cast<ConstantInt>(I->getOperand(1 - OpIdx))) {
+          if (C->isZero())
+            return false;
+        }
+      }
+    }
+  }
